private void xrTableCell68_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
    decimal erSoldAsHatEggs = 0;
    decimal esSoldAsHatEggs = 0;
    decimal erSoldAsTableEggs = 0;
    decimal esSoldAsTableEggs = 0;
    decimal erSendToOffal = 0;
    decimal esSendToOffal = 0;

    // --- Read values safely ---
    if (GetCurrentColumnValue("ER_SoldAsHatEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ER_SoldAsHatEggs").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ER_SoldAsHatEggs")) != 0)
    {
        erSoldAsHatEggs = Convert.ToDecimal(GetCurrentColumnValue("ER_SoldAsHatEggs"));
    }

    if (GetCurrentColumnValue("ES_SoldAsHatEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ES_SoldAsHatEggs").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ES_SoldAsHatEggs")) != 0)
    {
        esSoldAsHatEggs = Convert.ToDecimal(GetCurrentColumnValue("ES_SoldAsHatEggs"));
    }

    if (GetCurrentColumnValue("ER_SoldAsTableEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ER_SoldAsTableEggs").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ER_SoldAsTableEggs")) != 0)
    {
        erSoldAsTableEggs = Convert.ToDecimal(GetCurrentColumnValue("ER_SoldAsTableEggs"));
    }

    if (GetCurrentColumnValue("ES_SoldAsTableEggs") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ES_SoldAsTableEggs").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ES_SoldAsTableEggs")) != 0)
    {
        esSoldAsTableEggs = Convert.ToDecimal(GetCurrentColumnValue("ES_SoldAsTableEggs"));
    }

    if (GetCurrentColumnValue("ER_SendToOffal") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ER_SendToOffal").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ER_SendToOffal")) != 0)
    {
        erSendToOffal = Convert.ToDecimal(GetCurrentColumnValue("ER_SendToOffal"));
    }

    if (GetCurrentColumnValue("ES_SendToOffal") != null &&
        !string.IsNullOrEmpty(GetCurrentColumnValue("ES_SendToOffal").ToString()) &&
        Convert.ToDecimal(GetCurrentColumnValue("ES_SendToOffal")) != 0)
    {
        esSendToOffal = Convert.ToDecimal(GetCurrentColumnValue("ES_SendToOffal"));
    }

    // --- Equation ---
    total = (erSoldAsHatEggs + esSoldAsHatEggs) +
                    (erSoldAsTableEggs + esSoldAsTableEggs) +
                    (erSendToOffal + esSendToOffal);

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = total.ToString("0.##");   // format with 2 decimals


}

private void xrTableCell71_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal selChicks = 0;
decimal cullsChicks = 0;
decimal deadChicks = 0;
decimal settedEggs = 0;

// --- Read values directly ---
if (GetCurrentColumnValue("SelChicks") != null)
    selChicks = Convert.ToDecimal(GetCurrentColumnValue("SelChicks"));

if (GetCurrentColumnValue("CullsChicks") != null)
    cullsChicks = Convert.ToDecimal(GetCurrentColumnValue("CullsChicks"));

if (GetCurrentColumnValue("DeadChicks") != null)
    deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"));

if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Calculate CumHatchability ---
decimal cumHatchability = 0;
if (settedEggs != 0)
    cumHatchability = (selChicks + cullsChicks + deadChicks) / settedEggs * 100m;

decimal result = ( total * cumHatchability ) / settedEggs  * 100m;
// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with 2 decimals

}

private void xrTableCell74_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     // --- FarmInTake ---
    decimal farmInTake = 0;
    object valFarm = GetCurrentColumnValue("FarmInTake");
    if (valFarm != null && decimal.TryParse(valFarm.ToString(), out decimal tempFarm))
        farmInTake = tempFarm;

    // --- Total_RejEggs ---
    decimal totalRejEggs = 0;
    object valRej = GetCurrentColumnValue("Total_RejEggs");
    if (valRej != null && decimal.TryParse(valRej.ToString(), out decimal tempRej))
        totalRejEggs = tempRej;

    // --- BalOfHatEggs = FarmInTake - Total_RejEggs ---
    decimal balOfHatEggs = farmInTake - totalRejEggs;

    // --- SettedEggs ---
    decimal settedEggs = 0;
    object valSet = GetCurrentColumnValue("SettedEggs");
    if (valSet != null && decimal.TryParse(valSet.ToString(), out decimal tempSet))
        settedEggs = tempSet;

    // --- Final equation ---
    decimal result = balOfHatEggs - (settedEggs + total);

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
}

private void xrTableCell77_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      // --- Step 1: Read basic values ---
    decimal farmInTake = 0;
    object valFarm = GetCurrentColumnValue("FarmInTake");
    if (valFarm != null && decimal.TryParse(valFarm.ToString(), out decimal tempFarm))
        farmInTake = tempFarm;

    decimal settedEggs = 0;
    object valSetted = GetCurrentColumnValue("SettedEggs");
    if (valSetted != null && decimal.TryParse(valSetted.ToString(), out decimal tempSetted))
        settedEggs = tempSetted;

    decimal setEggBalHatEgg = 0;
    object valSetEgg = GetCurrentColumnValue("SetEggBalHatEgg");
    if (valSetEgg != null && decimal.TryParse(valSetEgg.ToString(), out decimal tempSetEgg))
        setEggBalHatEgg = tempSetEgg;

    // --- Step 2: Calculate Total_RejEggs ---
    decimal htRejBroken = 0, stRejBroken = 0;
    object valHtBroken = GetCurrentColumnValue("HT_RejBroken");
    if (valHtBroken != null && decimal.TryParse(valHtBroken.ToString(), out decimal tempHtBroken))
        htRejBroken = tempHtBroken;

    object valStBroken = GetCurrentColumnValue("ST_RejBroken");
    if (valStBroken != null && decimal.TryParse(valStBroken.ToString(), out decimal tempStBroken))
        stRejBroken = tempStBroken;

    decimal htRejCracks = 0, stRejCracks = 0;
    object valHtCracks = GetCurrentColumnValue("HT_RejCracks");
    if (valHtCracks != null && decimal.TryParse(valHtCracks.ToString(), out decimal tempHtCracks))
        htRejCracks = tempHtCracks;

    object valStCracks = GetCurrentColumnValue("ST_RejCracks");
    if (valStCracks != null && decimal.TryParse(valStCracks.ToString(), out decimal tempStCracks))
        stRejCracks = tempStCracks;

    decimal htRejDeformed = 0, stRejDeformed = 0;
    object valHtDeformed = GetCurrentColumnValue("HT_RejDeformed");
    if (valHtDeformed != null && decimal.TryParse(valHtDeformed.ToString(), out decimal tempHtDeformed))
        htRejDeformed = tempHtDeformed;

    object valStDeformed = GetCurrentColumnValue("ST_RejDeformed");
    if (valStDeformed != null && decimal.TryParse(valStDeformed.ToString(), out decimal tempStDeformed))
        stRejDeformed = tempStDeformed;

    decimal htRejOther = 0, stRejOther = 0;
    object valHtOther = GetCurrentColumnValue("HT_RejOther");
    if (valHtOther != null && decimal.TryParse(valHtOther.ToString(), out decimal tempHtOther))
        htRejOther = tempHtOther;

    object valStOther = GetCurrentColumnValue("ST_RejOther");
    if (valStOther != null && decimal.TryParse(valStOther.ToString(), out decimal tempStOther))
        stRejOther = tempStOther;

    decimal rejBroken = htRejBroken + stRejBroken;
    decimal rejCrack = htRejCracks + stRejCracks;
    decimal rejDef = htRejDeformed + stRejDeformed;
    decimal rejOther = htRejOther + stRejOther;

    decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

    // --- Step 3: Calculate BalOfHatEggs ---
    decimal balOfHatEggs = farmInTake - totalRejEggs;

    // --- Step 4: Calculate TotalEggSold ---
    decimal erSoldAsHatEggs = 0, esSoldAsHatEggs = 0;
    object valErHat = GetCurrentColumnValue("ER_SoldAsHatEggs");
    if (valErHat != null && decimal.TryParse(valErHat.ToString(), out decimal tempErHat))
        erSoldAsHatEggs = tempErHat;

    object valEsHat = GetCurrentColumnValue("ES_SoldAsHatEggs");
    if (valEsHat != null && decimal.TryParse(valEsHat.ToString(), out decimal tempEsHat))
        esSoldAsHatEggs = tempEsHat;

    decimal erSoldAsTableEggs = 0, esSoldAsTableEggs = 0;
    object valErTable = GetCurrentColumnValue("ER_SoldAsTableEggs");
    if (valErTable != null && decimal.TryParse(valErTable.ToString(), out decimal tempErTable))
        erSoldAsTableEggs = tempErTable;

    object valEsTable = GetCurrentColumnValue("ES_SoldAsTableEggs");
    if (valEsTable != null && decimal.TryParse(valEsTable.ToString(), out decimal tempEsTable))
        esSoldAsTableEggs = tempEsTable;

    decimal erSendToOffal = 0, esSendToOffal = 0;
    object valErOffal = GetCurrentColumnValue("ER_SendToOffal");
    if (valErOffal != null && decimal.TryParse(valErOffal.ToString(), out decimal tempErOffal))
        erSendToOffal = tempErOffal;

    object valEsOffal = GetCurrentColumnValue("ES_SendToOffal");
    if (valEsOffal != null && decimal.TryParse(valEsOffal.ToString(), out decimal tempEsOffal))
        esSendToOffal = tempEsOffal;

    decimal soldHatEggs = erSoldAsHatEggs + esSoldAsHatEggs;
    decimal soldTableEggs = erSoldAsTableEggs + esSoldAsTableEggs;
    decimal eggsToOffal = erSendToOffal + esSendToOffal;
    decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

    // --- Step 5: Calculate StockHatEggBal ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- Step 6: Calculate ActHatchBalanceEggs ---
    decimal actHatchBalanceEggs = 0;
    if (setEggBalHatEgg != 0)
    {
        decimal selChick = 0, culls = 0, deads = 0;

        object valSel = GetCurrentColumnValue("SelChickBalHatEgg");
        if (valSel != null && decimal.TryParse(valSel.ToString(), out decimal tempSel))
            selChick = tempSel;

        object valCulls = GetCurrentColumnValue("CullsBalHatEgg");
        if (valCulls != null && decimal.TryParse(valCulls.ToString(), out decimal tempCulls))
            culls = tempCulls;

        object valDeads = GetCurrentColumnValue("DeadsBalHatEgg");
        if (valDeads != null && decimal.TryParse(valDeads.ToString(), out decimal tempDeads))
            deads = tempDeads;

        actHatchBalanceEggs = (selChick + culls + deads) / setEggBalHatEgg * 100;
    }

    // --- Step 7: Final equation ---
    decimal result = stockHatEggBal * actHatchBalanceEggs / 100;

    // --- Assign result ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
}

