    decimal eggsToOffal = erSendToOffal + esSendToOffal;
    decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

    // --- STEP 5: Calculate StockHatEggBal ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- STEP 6: Calculate the difference ---
    decimal difference = settedEggs_1 - stockHatEggBal;

    // --- STEP 7: Apply condition ---
    decimal result = 0;
    if (difference >= 0)
    {
        result = difference;
    }

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
