    decimal soldTableEggs = erSoldAsTableEggs + esSoldAsTableEggs;
    decimal eggsToOffal = erSendToOffal + esSendToOffal;
    decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

    // --- STEP 5: Calculate StockHatEggBal ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- STEP 6: Calculate SettedEggs_1 (with condition) ---
    decimal settedEggs_1_Calculated = 0;
    decimal difference = settedEggs_1 - stockHatEggBal;
    if (difference >= 0)
    {
        settedEggs_1_Calculated = difference;
    }

    // --- STEP 7: Calculate GradeA_1 ---
    decimal gradeA_1 = 0;
    if (settedEggs_1 != 0)
    {
        gradeA_1 = selChicks_1 * (settedEggs_1_Calculated / settedEggs_1);
