        rejChicks_1 = (cullsChicks_1 + deadChicks_1) * (settedEggs_1_Calculated / settedEggs_1);
    }

    // --- STEP 9: Final Equation ---
    decimal total_1 = gradeA_1 + rejChicks_1;

