private void xrTableCell179_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // Helper method to safely get decimal value with null/empty checks
    decimal GetDecimalValue(string fieldName)
    {
        object value = GetCurrentColumnValue(fieldName);
        if (value != null && !string.IsNullOrEmpty(value.ToString()))
        {
            if (decimal.TryParse(value.ToString(), out decimal result))
                return result;
        }
        return 0;
    }

    // --- STEP 1: Read PART 1 values (for StockHatEggBal calculation) ---
    decimal farmInTake = GetDecimalValue("FarmInTake");
    decimal settedEggs = GetDecimalValue("SettedEggs");

    // --- Calculate Total_RejEggs for PART 1 ---
    decimal rejBroken = GetDecimalValue("HT_RejBroken") + GetDecimalValue("ST_RejBroken");
    decimal rejCrack = GetDecimalValue("HT_RejCracks") + GetDecimalValue("ST_RejCracks");
    decimal rejDef = GetDecimalValue("HT_RejDeformed") + GetDecimalValue("ST_RejDeformed");
    decimal rejOther = GetDecimalValue("HT_RejOther") + GetDecimalValue("ST_RejOther");
    decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

    // --- Calculate BalOfHatEggs for PART 1 ---
    decimal balOfHatEggs = farmInTake - totalRejEggs;

    // --- Calculate TotalEggSold for PART 1 ---
    decimal erSoldAsHatEggs = GetDecimalValue("ER_SoldAsHatEggs");
    decimal esSoldAsHatEggs = GetDecimalValue("ES_SoldAsHatEggs");
    decimal erSoldAsTableEggs = GetDecimalValue("ER_SoldAsTableEggs");
    decimal esSoldAsTableEggs = GetDecimalValue("ES_SoldAsTableEggs");
    decimal erSendToOffal = GetDecimalValue("ER_SendToOffal");
    decimal esSendToOffal = GetDecimalValue("ES_SendToOffal");

    decimal soldHatEggs = erSoldAsHatEggs + esSoldAsHatEggs;
    decimal soldTableEggs = erSoldAsTableEggs + esSoldAsTableEggs;
    decimal eggsToOffal = erSendToOffal + esSendToOffal;
    decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

    // --- Calculate StockHatEggBal for PART 1 ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- STEP 2: Read PART 2 values ---
    decimal farmInTake_1 = GetDecimalValue("FarmInTake_1");
    decimal settedEggs_1 = GetDecimalValue("SettedEggs_1");

    // --- Calculate Total_RejEggs_1 for PART 2 ---
    decimal rejBroken_1 = GetDecimalValue("HT_RejBroken_1") + GetDecimalValue("ST_RejBroken_1");
    decimal rejCrack_1 = GetDecimalValue("HT_RejCracks_1") + GetDecimalValue("ST_RejCracks_1");
    decimal rejDef_1 = GetDecimalValue("HT_RejDeformed_1") + GetDecimalValue("ST_RejDeformed_1");
    decimal rejOther_1 = GetDecimalValue("HT_RejOther_1") + GetDecimalValue("ST_RejOther_1");
    decimal totalRejEggs_1 = rejBroken_1 + rejCrack_1 + rejDef_1 + rejOther_1;

    // --- Calculate BalOfHatEggs_1 for PART 2 ---
    decimal balOfHatEggs_1 = farmInTake_1 - totalRejEggs_1;

    // --- Calculate SettedEggs_1 (with condition) ---
    decimal settedEggs_1_Calculated = 0;
    decimal difference = settedEggs_1 - stockHatEggBal;
    if (difference >= 0)
    {
        settedEggs_1_Calculated = difference;
    }

    // --- STEP 3: Calculate CumHatchability_1 ---
    decimal cumHatchability_1 = 0;

    // Check if SettedEggs_1 is not zero
    if (settedEggs_1 != 0)
    {
        decimal selChicks_1 = GetDecimalValue("SelChicks_1");
        decimal cullsChicks_1 = GetDecimalValue("CullsChicks_1");
        decimal deadChicks_1 = GetDecimalValue("DeadChicks_1");

        decimal totalChicks_1 = selChicks_1 + cullsChicks_1 + deadChicks_1;
        cumHatchability_1 = totalChicks_1 * 100 / settedEggs_1;
    }
    else
    {
        // Calculate ActHatchBalanceEggs
        decimal setEggBalHatEgg = GetDecimalValue("SetEggBalHatEgg");
        if (setEggBalHatEgg != 0)
        {
            decimal selChickBal = GetDecimalValue("SelChickBalHatEgg");
            decimal cullsBal = GetDecimalValue("CullsBalHatEgg");
            decimal deadsBal = GetDecimalValue("DeadsBalHatEgg");

            decimal totalBal = selChickBal + cullsBal + deadsBal;
            cumHatchability_1 = totalBal / setEggBalHatEgg * 100;
        }
    }

    // --- STEP 4: Final Equation ---
    decimal result = 0;
    decimal difference_1 = balOfHatEggs_1 - settedEggs_1_Calculated;
    result = difference_1 * cumHatchability_1 / 100;

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
  }

