{
    // Assuming SR_HT_FlkSumProdReport is the data source
    // You'll need to adjust this based on your actual data access method
    return GetFieldValue(fieldName);
}

// --- Calculate Part 1 components ---

// Rejected eggs for Part 1
decimal RejBroken = GetReportFieldValue("ST_RejBroken") + GetReportFieldValue("HT_RejBroken");
decimal RejCrack = GetReportFieldValue("ST_RejCracks") + GetReportFieldValue("HT_RejCracks");
decimal RejDef = GetReportFieldValue("HT_RejDeformed") + GetReportFieldValue("ST_RejDeformed");
decimal RejOther = GetReportFieldValue("ST_RejOther") + GetReportFieldValue("HT_RejOther");
decimal Total_RejEggs = RejBroken + RejCrack + RejDef + RejOther;

// Balance of Hatchery Eggs for Part 1
decimal FarmInTake = GetReportFieldValue("FarmInTake");
decimal BalOfHatEggs = FarmInTake - Total_RejEggs;

// Total Eggs Sold for Part 1
decimal SoldHatEggs = GetReportFieldValue("ER_SoldAsHatEggs") + GetReportFieldValue("ES_SoldAsHatEggs");
decimal SoldTableEggs = GetReportFieldValue("ER_SoldAsTableEggs") + GetReportFieldValue("ES_SoldAsTableEggs");
decimal EggsToOffal = GetReportFieldValue("ER_SendToOffal") + GetReportFieldValue("ES_SendToOffal");
decimal TotalEggSold = SoldHatEggs + SoldTableEggs + EggsToOffal;

// Stock Hatchery Egg Balance
decimal SettedEggs = GetReportFieldValue("SettedEggs");
decimal StockHatEggBal = BalOfHatEggs - (SettedEggs + TotalEggSold);

// --- Calculate Part 2 components ---

// Rejected eggs for Part 2
decimal RejBroken_1 = GetReportFieldValue("ST_RejBroken_1") + GetReportFieldValue("HT_RejBroken_1");
decimal RejCrack_1 = GetReportFieldValue("ST_RejCracks_1") + GetReportFieldValue("HT_RejCracks_1");
decimal RejDef_1 = GetReportFieldValue("HT_RejDeformed_1") + GetReportFieldValue("ST_RejDeformed_1");
decimal RejOther_1 = GetReportFieldValue("ST_RejOther_1") + GetReportFieldValue("HT_RejOther_1");
decimal Total_RejEggs_1 = RejBroken_1 + RejCrack_1 + RejDef_1 + RejOther_1;

// Balance of Hatchery Eggs for Part 2
decimal FarmInTake_1 = GetReportFieldValue("FarmInTake_1");
decimal BalOfHatEggs_1 = FarmInTake_1 - Total_RejEggs_1;

// Setted Eggs for Part 2 (with condition)
decimal SettedEggs_1_Raw = GetReportFieldValue("SettedEggs_1");
decimal SettedEggs_1 = 0;
decimal difference = SettedEggs_1_Raw - StockHatEggBal;
if (difference >= 0)
{
    SettedEggs_1 = difference;
}

// --- Calculate CumHatchability_1 ---
decimal CumHatchability_1 = 0;

if (SettedEggs_1_Raw != 0)
{
    decimal SelChicks_1 = GetReportFieldValue("SelChicks_1");
    decimal CullsChicks_1 = GetReportFieldValue("CullsChicks_1");
    decimal DeadChicks_1 = GetReportFieldValue("DeadChicks_1");

    decimal totalChicks = SelChicks_1 + CullsChicks_1 + DeadChicks_1;
    CumHatchability_1 = totalChicks * 100 / SettedEggs_1_Raw;
}
else
{
    decimal SetEggBalHatEgg = GetReportFieldValue("SetEggBalHatEgg");
    if (SetEggBalHatEgg != 0)
    {
        decimal SelChickBal = GetReportFieldValue("SelChickBalHatEgg");
        decimal CullsBal = GetReportFieldValue("CullsBalHatEgg");
        decimal DeadsBal = GetReportFieldValue("DeadsBalHatEgg");

        decimal totalBal = SelChickBal + CullsBal + DeadsBal;
        CumHatchability_1 = totalBal / SetEggBalHatEgg * 100;
    }
}

// --- Calculate EstChicks_PerEgg_1 ---
decimal EstChicks_PerEgg_1 = (BalOfHatEggs_1 - SettedEggs_1) * CumHatchability_1 / 100;

// --- Calculate CumChicks_1 ---
// Note: This calculation differs from the previous one
// Based on the formula: {@CumChicks_1}--->{@GradeA_1} + {@RejChicks_1}

// Calculate GradeA_1
decimal GradeA_1 = 0;
if (SettedEggs_1_Raw != 0)
{
    decimal SelChicks_1 = GetReportFieldValue("SelChicks_1");
    GradeA_1 = SelChicks_1 * (SettedEggs_1 / SettedEggs_1_Raw);
}

// Calculate RejChicks_1
decimal RejChicks_1 = 0;
if (SettedEggs_1_Raw != 0)
{
    decimal CullsChicks_1 = GetReportFieldValue("CullsChicks_1");
    decimal DeadChicks_1 = GetReportFieldValue("DeadChicks_1");
    RejChicks_1 = (CullsChicks_1 + DeadChicks_1) * (SettedEggs_1 / SettedEggs_1_Raw);
}

// Calculate CumChicks_1
decimal CumChicks_1 = GradeA_1 + RejChicks_1;

// --- Final Calculation ---
decimal result = EstChicks_PerEgg_1 + CumChicks_1;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N0");
 }

