private void xrTableCell246_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Helper function for safe parsing
decimal GetFieldValue(string fieldName)
{
    object value = GetCurrentColumnValue(fieldName);
    if (value != null && !string.IsNullOrEmpty(value.ToString()))
    {
        if (decimal.TryParse(value.ToString(), out decimal result))
            return result;
    }
    return 0;
}

// --- STEP 1: Calculate Part 1 components (for StockHatEggBal) ---

// Calculate rejection components for Part 1
decimal rejBroken = GetFieldValue("ST_RejBroken") + GetFieldValue("HT_RejBroken");
decimal rejCrack = GetFieldValue("ST_RejCracks") + GetFieldValue("HT_RejCracks");
decimal rejDef = GetFieldValue("HT_RejDeformed") + GetFieldValue("ST_RejDeformed");
decimal rejOther = GetFieldValue("ST_RejOther") + GetFieldValue("HT_RejOther");
decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

// Calculate BalOfHatEggs for Part 1
decimal farmInTake = GetFieldValue("FarmInTake");
decimal balOfHatEggs = farmInTake - totalRejEggs;

// Calculate TotalEggSold for Part 1
decimal soldHatEggs = GetFieldValue("ER_SoldAsHatEggs") + GetFieldValue("ES_SoldAsHatEggs");
decimal soldTableEggs = GetFieldValue("ER_SoldAsTableEggs") + GetFieldValue("ES_SoldAsTableEggs");
decimal eggsToOffal = GetFieldValue("ER_SendToOffal") + GetFieldValue("ES_SendToOffal");
decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

// Calculate StockHatEggBal
decimal settedEggs = GetFieldValue("SettedEggs");
decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

// --- STEP 2: Calculate Part 2 rejection components ---

// Calculate rejection components for Part 2
decimal rejBroken_1 = GetFieldValue("ST_RejBroken_1") + GetFieldValue("HT_RejBroken_1");
decimal rejCrack_1 = GetFieldValue("ST_RejCracks_1") + GetFieldValue("HT_RejCracks_1");
decimal rejDef_1 = GetFieldValue("HT_RejDeformed_1") + GetFieldValue("ST_RejDeformed_1");
decimal rejOther_1 = GetFieldValue("ST_RejOther_1") + GetFieldValue("HT_RejOther_1");
decimal totalRejEggs_1 = rejBroken_1 + rejCrack_1 + rejDef_1 + rejOther_1;

// Calculate BalOfHatEggs_1 for Part 2
decimal farmInTake_1 = GetFieldValue("FarmInTake_1");
decimal balOfHatEggs_1 = farmInTake_1 - totalRejEggs_1;

// --- STEP 3: Calculate SettedEggs_1 (adjusted) ---
decimal settedEggs_1_Raw = GetFieldValue("SettedEggs_1");
decimal settedEggs_1 = 0;
decimal difference = settedEggs_1_Raw - stockHatEggBal;
if (difference >= 0)
{
    settedEggs_1 = difference;
}

// --- STEP 4: Calculate CumHatchability_1 ---
decimal cumHatchability_1 = 0;

if (settedEggs_1_Raw != 0)
{
    decimal selChicks_1 = GetFieldValue("SelChicks_1");
    decimal cullsChicks_1 = GetFieldValue("CullsChicks_1");
    decimal deadChicks_1 = GetFieldValue("DeadChicks_1");

    decimal totalChicks_1 = selChicks_1 + cullsChicks_1 + deadChicks_1;
    cumHatchability_1 = totalChicks_1 * 100 / settedEggs_1_Raw;
}
else
{
    decimal setEggBalHatEgg = GetFieldValue("SetEggBalHatEgg");
    if (setEggBalHatEgg != 0)
    {
        decimal selChickBal = GetFieldValue("SelChickBalHatEgg");
        decimal cullsBal = GetFieldValue("CullsBalHatEgg");
        decimal deadsBal = GetFieldValue("DeadsBalHatEgg");

        decimal totalBal = selChickBal + cullsBal + deadsBal;
        cumHatchability_1 = totalBal / setEggBalHatEgg * 100;
    }
}

// --- STEP 5: Calculate EstChicks_PerEgg_1 ---
decimal estChicks_PerEgg_1 = (balOfHatEggs_1 - settedEggs_1) * cumHatchability_1 / 100;

// --- STEP 6: Calculate GradeA_1 ---
decimal gradeA_1 = 0;
if (settedEggs_1_Raw != 0)
{
    decimal selChicks_1 = GetFieldValue("SelChicks_1");
    gradeA_1 = selChicks_1 * (settedEggs_1 / settedEggs_1_Raw);
}

// --- STEP 7: Calculate RejChicks_1 ---
decimal rejChicks_1 = 0;
if (settedEggs_1_Raw != 0)
{
    decimal cullsChicks_1 = GetFieldValue("CullsChicks_1");
    decimal deadChicks_1 = GetFieldValue("DeadChicks_1");
    rejChicks_1 = (cullsChicks_1 + deadChicks_1) * (settedEggs_1 / settedEggs_1_Raw);
}

// --- STEP 8: Calculate CumChicks_1 ---
decimal cumChicks_1 = gradeA_1 + rejChicks_1;

// --- STEP 9: Calculate CumChicks_Act_Est_1 ---
decimal cumChicks_Act_Est_1 = estChicks_PerEgg_1 + cumChicks_1;

// --- STEP 10: Get POL and calculate the ratio ---
decimal pol = GetFieldValue("POL");
decimal result = 0;

if (pol != 0)
{
    result = cumChicks_Act_Est_1 / pol;
}

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");
    }

