        object valCulls1 = GetCurrentColumnValue("CullsChicks_1");
        if (valCulls1 != null && !string.IsNullOrEmpty(valCulls1.ToString()))
        {
            if (decimal.TryParse(valCulls1.ToString(), out decimal tempCulls1))
                cullsChicks_1 = tempCulls1;
        }

        decimal deadChicks_1 = 0;
        object valDead1 = GetCurrentColumnValue("DeadChicks_1");
        if (valDead1 != null && !string.IsNullOrEmpty(valDead1.ToString()))
        {
            if (decimal.TryParse(valDead1.ToString(), out decimal tempDead1))
                deadChicks_1 = tempDead1;
        }

        // Calculate: (SelChicks_1 + CullsChicks_1 + DeadChicks_1) * 100 / SettedEggs_1
        decimal totalChicks_1 = selChicks_1 + cullsChicks_1 + deadChicks_1;
        result = totalChicks_1 * 100 / settedEggs_1;
    }
    else
    {
        // --- Read values for ActHatchBalanceEggs calculation ---
        decimal setEggBalHatEgg = 0;
        object valSetEgg = GetCurrentColumnValue("SetEggBalHatEgg");
        if (valSetEgg != null && !string.IsNullOrEmpty(valSetEgg.ToString()))
        {
            if (decimal.TryParse(valSetEgg.ToString(), out decimal tempSetEgg))
                setEggBalHatEgg = tempSetEgg;
        }

        // Calculate ActHatchBalanceEggs: if SetEggBalHatEgg <> 0
        decimal actHatchBalanceEggs = 0;
        if (setEggBalHatEgg != 0)
        {
            decimal selChickBal = 0;
            object valSelBal = GetCurrentColumnValue("SelChickBalHatEgg");
            if (valSelBal != null && !string.IsNullOrEmpty(valSelBal.ToString()))
            {
                if (decimal.TryParse(valSelBal.ToString(), out decimal tempSelBal))
