                if (decimal.TryParse(valDeadsBal.ToString(), out decimal tempDeadsBal))
                    deadsBal = tempDeadsBal;
            }

            decimal totalBal = selChickBal + cullsBal + deadsBal;
            actHatchBalanceEggs = totalBal / setEggBalHatEgg * 100;
        }

        result = actHatchBalanceEggs;
