private void xrTableCell168_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // Helper function for safe parsing
    decimal GetFieldValue(string fieldName)
    {
        object value = GetCurrentColumnValue(fieldName);
        if (value != null && !string.IsNullOrEmpty(value.ToString()))
        {
            if (decimal.TryParse(value.ToString(), out decimal result))
                return result;
        }
        return 0;
    }

    // --- STEP 1: Read all basic values ---
    decimal farmInTake = GetFieldValue("FarmInTake");
    decimal settedEggs = GetFieldValue("SettedEggs");
    decimal settedEggs_1 = GetFieldValue("SettedEggs_1");
    decimal selChicks_1 = GetFieldValue("SelChicks_1");

    // --- STEP 2: Calculate Total_RejEggs ---
    decimal rejBroken = GetFieldValue("HT_RejBroken") + GetFieldValue("ST_RejBroken");
    decimal rejCrack = GetFieldValue("HT_RejCracks") + GetFieldValue("ST_RejCracks");
    decimal rejDef = GetFieldValue("HT_RejDeformed") + GetFieldValue("ST_RejDeformed");
    decimal rejOther = GetFieldValue("HT_RejOther") + GetFieldValue("ST_RejOther");
    decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

    // --- STEP 3: Calculate BalOfHatEggs ---
    decimal balOfHatEggs = farmInTake - totalRejEggs;

    // --- STEP 4: Calculate TotalEggSold ---
    decimal erSoldAsHatEggs = GetFieldValue("ER_SoldAsHatEggs");
    decimal esSoldAsHatEggs = GetFieldValue("ES_SoldAsHatEggs");
    decimal erSoldAsTableEggs = GetFieldValue("ER_SoldAsTableEggs");
    decimal esSoldAsTableEggs = GetFieldValue("ES_SoldAsTableEggs");
    decimal erSendToOffal = GetFieldValue("ER_SendToOffal");
    decimal esSendToOffal = GetFieldValue("ES_SendToOffal");

    decimal soldHatEggs = erSoldAsHatEggs + esSoldAsHatEggs;
    decimal soldTableEggs = erSoldAsTableEggs + esSoldAsTableEggs;
    decimal eggsToOffal = erSendToOffal + esSendToOffal;
    decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

    // --- STEP 5: Calculate StockHatEggBal ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- STEP 6: Calculate SettedEggs_1 (with condition) ---
    decimal settedEggs_1_Calculated = 0;
    decimal difference = settedEggs_1 - stockHatEggBal;
    if (difference >= 0)
    {
        settedEggs_1_Calculated = difference;
    }

    // --- STEP 7: Main Equation ---
    decimal result = 0;
    if (settedEggs_1 != 0)
    {
        decimal ratio = settedEggs_1_Calculated / settedEggs_1;
        result = selChicks_1 * ratio;
    }

    // --- Assign result to cell ---
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("0.##");
}

