decimal rejDef = GetFieldValue("HT_RejDeformed") + GetFieldValue("ST_RejDeformed");
decimal rejOther = GetFieldValue("ST_RejOther") + GetFieldValue("HT_RejOther");
decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

// --- Calculate Part 2 rejection components ---
decimal rejBroken_1 = GetFieldValue("ST_RejBroken_1") + GetFieldValue("HT_RejBroken_1");
decimal rejCrack_1 = GetFieldValue("ST_RejCracks_1") + GetFieldValue("HT_RejCracks_1");
decimal rejDef_1 = GetFieldValue("HT_RejDeformed_1") + GetFieldValue("ST_RejDeformed_1");
decimal rejOther_1 = GetFieldValue("ST_RejOther_1") + GetFieldValue("HT_RejOther_1");
decimal totalRejEggs_1 = rejBroken_1 + rejCrack_1 + rejDef_1 + rejOther_1;

// --- Get POL value ---
decimal pol = GetFieldValue("POL");

// --- Calculate the ratios ---
decimal totalRejEggs_HH = 0;
decimal totalRejEggs_HH_1 = 0;

if (pol != 0)
{
    totalRejEggs_HH = totalRejEggs / pol;
    totalRejEggs_HH_1 = totalRejEggs_1 / pol;
}

// --- Calculate the sum ---
decimal result = totalRejEggs_HH + totalRejEggs_HH_1;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");
}

private void xrTableCell258_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Helper function for safe parsing
decimal GetFieldValue(string fieldName)
{
    object value = GetCurrentColumnValue(fieldName);
    if (value != null && !string.IsNullOrEmpty(value.ToString()))
    {
        if (decimal.TryParse(value.ToString(), out decimal result))
            return result;
    }
    return 0;
}

// --- Calculate Part 1 components ---

// Calculate rejection components for Part 1
decimal rejBroken = GetFieldValue("ST_RejBroken") + GetFieldValue("HT_RejBroken");
decimal rejCrack = GetFieldValue("ST_RejCracks") + GetFieldValue("HT_RejCracks");
decimal rejDef = GetFieldValue("HT_RejDeformed") + GetFieldValue("ST_RejDeformed");
decimal rejOther = GetFieldValue("ST_RejOther") + GetFieldValue("HT_RejOther");
decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;

// Calculate BalOfHatEggs for Part 1
decimal farmInTake = GetFieldValue("FarmInTake");
decimal balOfHatEggs = farmInTake - totalRejEggs;

// --- Calculate Part 2 components ---

// Calculate rejection components for Part 2
decimal rejBroken_1 = GetFieldValue("ST_RejBroken_1") + GetFieldValue("HT_RejBroken_1");
decimal rejCrack_1 = GetFieldValue("ST_RejCracks_1") + GetFieldValue("HT_RejCracks_1");
decimal rejDef_1 = GetFieldValue("HT_RejDeformed_1") + GetFieldValue("ST_RejDeformed_1");
decimal rejOther_1 = GetFieldValue("ST_RejOther_1") + GetFieldValue("HT_RejOther_1");
decimal totalRejEggs_1 = rejBroken_1 + rejCrack_1 + rejDef_1 + rejOther_1;

// Calculate BalOfHatEggs_1 for Part 2
decimal farmInTake_1 = GetFieldValue("FarmInTake_1");
decimal balOfHatEggs_1 = farmInTake_1 - totalRejEggs_1;

// --- Get POL value ---
decimal pol = GetFieldValue("POL");

// --- Calculate the ratios ---
decimal cumFinalHatEgg_HH = 0;
decimal cumHatEgg_HH_1 = 0;

if (pol != 0)
{
    cumFinalHatEgg_HH = balOfHatEggs / pol;
    cumHatEgg_HH_1 = balOfHatEggs_1 / pol;
}

// --- Calculate the sum ---
decimal result = cumFinalHatEgg_HH + cumHatEgg_HH_1;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");
}

private void xrTableCell261_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Helper function for safe conversion
decimal SafeConvert(object value)
{
    if (value == null || value == DBNull.Value || string.IsNullOrEmpty(value.ToString()))
        return 0;
    return Convert.ToDecimal(value);
}

// ==================== Get All Raw Values - Set 1 ====================
decimal stRejBroken = SafeConvert(GetCurrentColumnValue("ST_RejBroken"));
decimal htRejBroken = SafeConvert(GetCurrentColumnValue("HT_RejBroken"));
decimal stRejCracks = SafeConvert(GetCurrentColumnValue("ST_RejCracks"));
decimal htRejCracks = SafeConvert(GetCurrentColumnValue("HT_RejCracks"));
decimal htRejDeformed = SafeConvert(GetCurrentColumnValue("HT_RejDeformed"));
decimal stRejDeformed = SafeConvert(GetCurrentColumnValue("ST_RejDeformed"));
decimal stRejOther = SafeConvert(GetCurrentColumnValue("ST_RejOther"));
decimal htRejOther = SafeConvert(GetCurrentColumnValue("HT_RejOther"));
decimal farmInTake = SafeConvert(GetCurrentColumnValue("FarmInTake"));
decimal settledEggs = SafeConvert(GetCurrentColumnValue("SettedEggs"));
decimal selChicks = SafeConvert(GetCurrentColumnValue("SelChicks"));
decimal cullsChicks = SafeConvert(GetCurrentColumnValue("CullsChicks"));
decimal deadChicks = SafeConvert(GetCurrentColumnValue("DeadChicks"));
decimal pol = SafeConvert(GetCurrentColumnValue("POL"));
decimal erSoldAsHatEggs = SafeConvert(GetCurrentColumnValue("ER_SoldAsHatEggs"));
decimal esSoldAsHatEggs = SafeConvert(GetCurrentColumnValue("ES_SoldAsHatEggs"));
decimal erSoldAsTableEggs = SafeConvert(GetCurrentColumnValue("ER_SoldAsTableEggs"));
decimal esSoldAsTableEggs = SafeConvert(GetCurrentColumnValue("ES_SoldAsTableEggs"));
decimal erSendToOffal = SafeConvert(GetCurrentColumnValue("ER_SendToOffal"));
decimal esSendToOffal = SafeConvert(GetCurrentColumnValue("ES_SendToOffal"));
decimal setEggBalHatEgg = SafeConvert(GetCurrentColumnValue("SetEggBalHatEgg"));
decimal selChickBalHatEgg = SafeConvert(GetCurrentColumnValue("SelChickBalHatEgg"));
decimal cullsBalHatEgg = SafeConvert(GetCurrentColumnValue("CullsBalHatEgg"));
decimal deadsBalHatEgg = SafeConvert(GetCurrentColumnValue("DeadsBalHatEgg"));

// ==================== Get All Raw Values - Set 2 ====================
decimal farmInTake_1 = SafeConvert(GetCurrentColumnValue("FarmInTake_1"));
decimal settledEggs_1 = SafeConvert(GetCurrentColumnValue("SettedEggs_1"));
decimal selChicks_1 = SafeConvert(GetCurrentColumnValue("SelChicks_1"));
decimal cullsChicks_1 = SafeConvert(GetCurrentColumnValue("CullsChicks_1"));
decimal deadChicks_1 = SafeConvert(GetCurrentColumnValue("DeadChicks_1"));
decimal stRejBroken_1 = SafeConvert(GetCurrentColumnValue("ST_RejBroken_1"));
decimal htRejBroken_1 = SafeConvert(GetCurrentColumnValue("HT_RejBroken_1"));
decimal stRejCracks_1 = SafeConvert(GetCurrentColumnValue("ST_RejCracks_1"));
decimal htRejCracks_1 = SafeConvert(GetCurrentColumnValue("HT_RejCracks_1"));
decimal htRejDeformed_1 = SafeConvert(GetCurrentColumnValue("HT_RejDeformed_1"));
decimal stRejDeformed_1 = SafeConvert(GetCurrentColumnValue("ST_RejDeformed_1"));
decimal stRejOther_1 = SafeConvert(GetCurrentColumnValue("ST_RejOther_1"));
decimal htRejOther_1 = SafeConvert(GetCurrentColumnValue("HT_RejOther_1"));
decimal erSoldAsHatEggs_1 = SafeConvert(GetCurrentColumnValue("ER_SoldAsHatEggs_1"));
decimal esSoldAsHatEggs_1 = SafeConvert(GetCurrentColumnValue("ES_SoldAsHatEggs_1"));
decimal erSoldAsTableEggs_1 = SafeConvert(GetCurrentColumnValue("ER_SoldAsTableEggs_1"));
decimal esSoldAsTableEggs_1 = SafeConvert(GetCurrentColumnValue("ES_SoldAsTableEggs_1"));
decimal erSendToOffal_1 = SafeConvert(GetCurrentColumnValue("ER_SendToOffal_1"));
decimal esSendToOffal_1 = SafeConvert(GetCurrentColumnValue("ES_SendToOffal_1"));
decimal setEggBalHatEgg_1 = SafeConvert(GetCurrentColumnValue("SetEggBalHatEgg_1"));
decimal selChickBalHatEgg_1 = SafeConvert(GetCurrentColumnValue("SelChickBalHatEgg_1"));
decimal cullsBalHatEgg_1 = SafeConvert(GetCurrentColumnValue("CullsBalHatEgg_1"));
decimal deadsBalHatEgg_1 = SafeConvert(GetCurrentColumnValue("DeadsBalHatEgg_1"));

// ==================== Set 1 Calculations ====================
decimal rejBroken = stRejBroken + htRejBroken;
decimal rejCrack = stRejCracks + htRejCracks;
decimal rejDef = htRejDeformed + stRejDeformed;
decimal rejOther = stRejOther + htRejOther;
decimal totalRejEggs = rejBroken + rejCrack + rejDef + rejOther;
decimal balOfHatEggs = farmInTake - totalRejEggs;

decimal soldHatEggs = erSoldAsHatEggs + esSoldAsHatEggs;
decimal soldTableEggs = erSoldAsTableEggs + esSoldAsTableEggs;
decimal eggsToOffal = erSendToOffal + esSendToOffal;
decimal totalEggSold = soldHatEggs + soldTableEggs + eggsToOffal;

decimal stockHatEggBal = balOfHatEggs - (settledEggs + totalEggSold);

decimal actHatchBalanceEggs = 0;
if (setEggBalHatEgg != 0)
{
    actHatchBalanceEggs = ((selChickBalHatEgg + cullsBalHatEgg + deadsBalHatEgg) / setEggBalHatEgg) * 100.0m;
}

decimal estChicksPerStock_HE = (stockHatEggBal * actHatchBalanceEggs) / 100.0m;

decimal cumHatchability = 0;
if (settledEggs != 0)
{
    cumHatchability = ((selChicks + cullsChicks + deadChicks) / settledEggs) * 100.0m;
}

decimal estChicksPerEgg = 0;
if (totalEggSold != 0)
{
    estChicksPerEgg = totalEggSold * cumHatchability / 100.0m;
}

decimal cumChicks = selChicks + cullsChicks + deadChicks;
decimal cumChicks_Act_Est = estChicksPerEgg + estChicksPerStock_HE + cumChicks;

decimal cumChicks_ActEst_HH = 0;
if (pol != 0)
{
    cumChicks_ActEst_HH = cumChicks_Act_Est / pol;
}

decimal cumFinalHatEgg_HH = 0;
if (pol != 0)
{
    cumFinalHatEgg_HH = balOfHatEggs / pol;
}

// ==================== Set 2 Calculations ====================
decimal rejBroken_1 = stRejBroken_1 + htRejBroken_1;
decimal rejCrack_1 = stRejCracks_1 + htRejCracks_1;
decimal rejDef_1 = htRejDeformed_1 + stRejDeformed_1;
decimal rejOther_1 = stRejOther_1 + htRejOther_1;
decimal totalRejEggs_1 = rejBroken_1 + rejCrack_1 + rejDef_1 + rejOther_1;
decimal balOfHatEggs_1 = farmInTake_1 - totalRejEggs_1;

decimal soldHatEggs_1 = erSoldAsHatEggs_1 + esSoldAsHatEggs_1;
decimal soldTableEggs_1 = erSoldAsTableEggs_1 + esSoldAsTableEggs_1;
decimal eggsToOffal_1 = erSendToOffal_1 + esSendToOffal_1;
decimal totalEggSold_1 = soldHatEggs_1 + soldTableEggs_1 + eggsToOffal_1;

decimal stockHatEggBal_1 = balOfHatEggs_1 - (settledEggs_1 + totalEggSold_1);

decimal actHatchBalanceEggs_1 = 0;
if (setEggBalHatEgg_1 != 0)
{
    actHatchBalanceEggs_1 = ((selChickBalHatEgg_1 + cullsBalHatEgg_1 + deadsBalHatEgg_1) / setEggBalHatEgg_1) * 100.0m;
}

decimal cumHatchability_1 = 0;
if (settledEggs_1 != 0)
{
    cumHatchability_1 = ((selChicks_1 + cullsChicks_1 + deadChicks_1) * 100) / settledEggs_1;
}
else
{
    cumHatchability_1 = actHatchBalanceEggs;
}

decimal settedEggs_1_adj = 0;
if (settledEggs_1 - stockHatEggBal < 0)
{
    settedEggs_1_adj = 0;
}
else
{
    settedEggs_1_adj = settledEggs_1 - stockHatEggBal;
}

decimal gradeA_1 = 0;
if (settledEggs_1 != 0)
{
    gradeA_1 = selChicks_1 * (settedEggs_1_adj / settledEggs_1);
}

decimal rejChicks_1 = 0;
if (settledEggs_1 != 0)
{
    rejChicks_1 = (cullsChicks_1 + deadChicks_1) * (settedEggs_1_adj / settledEggs_1);
}

decimal cumChicks_1 = gradeA_1 + rejChicks_1;

decimal estChicks_PerEgg_1 = 0;
if (balOfHatEggs_1 - settledEggs_1 > 0)
{
    estChicks_PerEgg_1 = (balOfHatEggs_1 - settledEggs_1) * cumHatchability_1 / 100.0m;
}

decimal cumChicks_Act_Est_1 = estChicks_PerEgg_1 + cumChicks_1;

decimal cumChicks_ActEst_HH_1 = 0;
if (pol != 0)
{
    cumChicks_ActEst_HH_1 = cumChicks_Act_Est_1 / pol;
}

decimal cumHatEgg_HH_1 = 0;
if (pol != 0)
{
    cumHatEgg_HH_1 = balOfHatEggs_1 / pol;
}

// ==================== Final Calculations ====================
decimal abCumHatchEggsHH = cumFinalHatEgg_HH + cumHatEgg_HH_1;
decimal abCumTotalChicksHH = cumChicks_ActEst_HH + cumChicks_ActEst_HH_1;

// ==================== Final Result ====================
if (abCumHatchEggsHH != 0)
{
    decimal result = (abCumTotalChicksHH / abCumHatchEggsHH) * 100.0m;
    result = Math.Round(result, 2);
    cell.Text = result.ToString("N2") ;
}
else
{
    cell.Text = "0.00";
}

   }

